368	            };
369	        }
370	    }
371	
372	    // Check for home directory references that could escape workspace.
373	    if command.contains("~/") || command.contains("$HOME") {
374	        return ValidationResult::Warn {
375	            message:
376	                "Command references home directory — verify it stays within the workspace scope"
377	                    .to_string(),
378	        };
379	    }
380	
381	    ValidationResult::Allow
382	}
